      "short_broadband_sweep_most_microbats_e": "Short broadband sweep. Most microbats. Excellent range/distance.",
      "mixed_cf_fm": "🎶 Mixed CF-FM",
      "long_tailed_bat_style_long_cf_terminal": "Long-tailed bat style. Long CF + terminal FM chirp.",
