    "simulators": {
      "heading": "Disability simulators",
      "description": "Toggle a simulator to apply a CSS filter to the page behind this lab. The lab itself stays unfiltered so you can keep using these controls. Click a tile to enable; click again to disable. Only one simulator runs at a time.",
      "framing_strong": "Important framing: ",
      "framing_body": "simulators are imperfect approximations. They are useful for empathy-building and quick checks, NOT for verifying compliance. A protanopia filter is NOT the same as protanopia. Real users have lived with their condition; you are seeing it for 60 seconds. Use simulators to surface obvious problems (color-only information, low contrast, illegible text), then test with real users when stakes matter.",
      "active_suffix": "· active",
      "info_suffix": "· info",
      "blur_amount_label": "Blur amount: ",
      "blur_amount_hint": "(2px ≈ mild low vision; 5-8px ≈ severe)",
      "blur_amount_aria": "Blur amount in pixels",
      "stop": "Stop simulator",
      "motor_toast": "Motor impairment simulation: see the info card.",
      "tip": "Tip: try the color-blindness simulators on a lesson that uses red/green to convey meaning (correct/incorrect, warning/safe). If the meaning is lost in the simulation, the original design is failing students with that condition. Add icons, labels, or patterns alongside color.",
      "items": {
        "blur_label": "Low-vision blur",
        "blur_desc": "Approximates uncorrected low vision (visual acuity worse than 20/40). Roughly 4% of the population has uncorrected refractive error or other low-vision conditions; this share is much higher among older adults and students with visual impairments.",
        "protanopia_label": "Protanopia (red-blind)",
        "protanopia_desc": "Severe red-green color vision deficiency, missing the L-cone. About 1% of males and very rare in females. Reds appear darker; reds and greens are confused.",
        "deuteranopia_label": "Deuteranopia (green-blind)",
        "deuteranopia_desc": "The most common form of color blindness, missing the M-cone. About 6% of males. Reds and greens appear similar; the most common form of red-green color vision deficiency.",
        "tritanopia_label": "Tritanopia (blue-blind)",
        "tritanopia_desc": "Rare form, missing the S-cone. About 0.01% of the population. Blues appear greenish; yellow-blue distinctions are lost.",
        "achromatopsia_label": "Achromatopsia (no color)",
        "achromatopsia_desc": "Complete absence of color vision. Affects roughly 0.003% of the population (about 1 in 30,000). The world appears in shades of grey.",
        "dyslexia_label": "Dyslexia visual stress",
        "dyslexia_desc": "A LIMITED simulation of one common visual-stress experience some dyslexic readers report (slight blur, lower contrast, shifting spacing). Dyslexia is highly individual; this is one slice, not a definitive rendering. About 5-10% of students have dyslexia.",
        "motor_label": "Motor impairments",
        "motor_desc": "Motor impairments resist visual simulation. The most authentic test is to use the OS-level tools real students use: Windows Sticky Keys, macOS Slow Keys, dwell-click software, switch access (e.g., the iOS Switch Control or Android Switch Access). Try completing a lesson using only one hand, only the keyboard, or only one finger."
      }
    }
